    pdfUrls:['http://www.dawlati.gov.lb/documents/10180/576166/%D8%B7%D9%84%D8%A8%20%D8%A5%D8%AC%D8%A7%D8%B2%D8%A9%20%D8%B9%D9%85%D9%84.pdf'],
    hasForm:true,
